#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int search(vector<int>& arr, int X) {
        int left = 0, right = arr.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (arr[mid] == X) return mid;
            else if (arr[mid] < X) left = mid + 1;
            else right = mid - 1;
        }
        return -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int X;
    if (!(cin >> X)) return 0;
    Solution sol;
    int ans = sol.search(arr, X);
    cout << ans << '\n';
    return 0;
}
